// Normaliza payload de qualquer fonte para o contrato canônico do Cérebro
const root = $json;
const src = (root.body && typeof root.body === 'object' && !Array.isArray(root.body))
  ? { ...root, ...root.body }
  : root;

function toText(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  if (Array.isArray(v)) return v.map(toText).join('\n');
  if (typeof v === 'object') {
    if (v.text != null) return toText(v.text);
    if (v.mensagem != null) return toText(v.mensagem);
    if (v.content != null) return toText(v.content);
    if (v.body != null) return toText(v.body);
    return '';
  }
  return String(v);
}

function toCliente(v) {
  if (!v) return 'Cliente';
  if (typeof v === 'string') return v.trim() || 'Cliente';
  if (typeof v === 'object') {
    const n = v.name || v.nome || v.pushName || '';
    return String(n).trim() || 'Cliente';
  }
  return 'Cliente';
}

const mensagem = toText(
  src.mensagem ?? src.message ?? src.mensagens ?? src.messages ??
  (typeof src.body === 'string' ? src.body : '') ?? ''
).replace(/\s+/g, ' ').trim();

if (!mensagem || mensagem.length < 1) {
  throw new Error('Payload sem mensagem valida');
}

const ticketRaw = src.ticket_id ?? src.ticket?.id ?? src.conversation_id ?? src.conversationId ?? '';
const ticket_id = String(ticketRaw).trim() || ('auto-' + Date.now());

const cliente_nome = toCliente(
  typeof src.cliente === 'object' && src.cliente !== null
    ? src.cliente
    : src.contact || src.customer || (typeof src.cliente === 'string' ? src.cliente : null)
);

const canal = src.canal ?? src.channel ?? src.source ?? 'webhook';

const sourceSystem = src.metadata?.sourceSystem ?? src.source_system ?? src.sourceSystem ?? 'n8n-webhook';
const sourceEntityId = src.metadata?.sourceEntityId ?? src.source_entity_id ?? ticket_id;
const tenantId = src.metadata?.tenantId ?? src.tenant_id ?? src.organization_id ?? 'default';
const ingestionId = src.metadata?.ingestionId ?? src.ingestion_id ?? ('ing-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8));
const dataEvento = src.data_evento ?? src.dataEvento ?? src.timestamp ?? new Date().toISOString();
const tecnico = src.tecnico ?? src.agent ?? src.assignee ?? 'n8n';

return [{
  json: {
    ticket_id,
    cliente: cliente_nome,
    canal,
    mensagens: mensagem,
    tecnico,
    data_evento: dataEvento,
    metadata: {
      sourceSystem,
      sourceEntityId,
      tenantId,
      ingestionId
    },
    _texto_consulta: mensagem
  }
}];

const query = $json;
const ingest = $('3. Ingerir no Cerebro (/api/ingestao/v1/events)').item.json;
const normalizado = $('2. Normalizar Payload (universal)').item.json;

return [{
  json: {
    status: 'processado',
    atendimento_id: ingest.atendimento_id,
    ticket_id: normalizado.ticket_id,
    cliente: normalizado.cliente,
    canal: normalizado.canal,
    confianca: query.confianca,
    resposta_sugerida: query.resposta,
    casos_encontrados: query.casos?.length ?? 0,
    audience: query.audience,
    timestamp: new Date().toISOString()
  }
}];

const ingest = $('3. Ingerir no Cerebro (/api/ingestao/v1/events)').item.json;
const normalizado = $('2. Normalizar Payload (universal)').item.json;

return [{
  json: {
    status: 'duplicate_ignored',
    ticket_id: normalizado.ticket_id,
    dedup_key: ingest.dedupKey ?? 'N/A',
    message: 'Evento ja processado anteriormente — ignorado por deduplicacao',
    timestamp: new Date().toISOString()
  }
}];
